# Add to existing aws_wafv2_web_acl rule list (COUNT first)
rule {
  name     = "ja3-allowlist-monitor-sensitive"
  priority = 210

  action {
    count {}
  }

  statement {
    and_statement {
      # 1) Sensitive endpoint scope
      statement {
        byte_match_statement {
          field_to_match { uri_path {} }
          positional_constraint = "STARTS_WITH"
          search_string         = "/login"
          text_transformation {
            priority = 0
            type     = "NONE"
          }
        }
      }

      # 2) JA3 context/label present (implementation depends on your log-label pipeline)
      statement {
        label_match_statement {
          scope = "LABEL"
          key   = "awswaf:request:tls:ja3:present"
        }
      }

      # 3) Not in trusted JA3 allowlist
      statement {
        not_statement {
          statement {
            regex_pattern_set_reference_statement {
              arn = aws_wafv2_regex_pattern_set.trusted_ja3.arn
              field_to_match {
                single_header { name = "x-ja3-fingerprint" }
              }
              text_transformation {
                priority = 0
                type     = "LOWERCASE"
              }
            }
          }
        }
      }
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "ja3AllowlistMonitorSensitive"
    sampled_requests_enabled   = true
  }
}

# Optional second rule: context absent on sensitive paths (COUNT only)
rule {
  name     = "ja3-context-absent-monitor-sensitive"
  priority = 211

  action {
    count {}
  }

  statement {
    and_statement {
      statement {
        byte_match_statement {
          field_to_match { uri_path {} }
          positional_constraint = "STARTS_WITH"
          search_string         = "/login"
          text_transformation {
            priority = 0
            type     = "NONE"
          }
        }
      }
      statement {
        not_statement {
          statement {
            label_match_statement {
              scope = "LABEL"
              key   = "awswaf:request:tls:ja3:present"
            }
          }
        }
      }
    }
  }

  visibility_config {
    cloudwatch_metrics_enabled = true
    metric_name                = "ja3ContextAbsentSensitive"
    sampled_requests_enabled   = true
  }
}

# Example trusted set placeholder
resource "aws_wafv2_regex_pattern_set" "trusted_ja3" {
  name  = "trusted-ja3-fingerprints"
  scope = "REGIONAL" # or CLOUDFRONT

  regular_expression {
    regex_string = "^(771,4865-4866-4867,0-23-65281,29-23-24,0)$"
  }
}
